// Extract inventory data from Shopify webhook
// Shopify sends: { inventory_item_id, location_id, available, updated_at }
const body = $input.first().json.body;

const stock = parseInt(body.available, 10);
const THRESHOLD = parseInt(process.env.STOCK_THRESHOLD || '10', 10);

return [{
  json: {
    inventory_item_id: body.inventory_item_id,
    location_id: body.location_id,
    available: stock,
    threshold: THRESHOLD,
    is_low: !isNaN(stock) && stock <= THRESHOLD,
    updated_at: body.updated_at,
    raw: body
  }
}];

// No alert needed — stock is above threshold
const inventory = $input.first().json;
return [{
  json: {
    skipped: true,
    reason: `Stock at ${inventory.available} is above threshold of ${inventory.threshold}`,
    available: inventory.available
  }
}];

// Build email notification content from AI-generated copy
const alertData = $input.first().json;
const alert = alertData.alert || {};
const copy = alertData.copy || {};

const alertTypeLabels = {
  'out_of_stock': '🚨 OUT OF STOCK',
  'critical_low': '🔴 CRITICAL LOW STOCK',
  'low_stock': '🟡 LOW STOCK ALERT'
};

const typeLabel = alertTypeLabels[alert.alert_type] || '⚠️ STOCK ALERT';

return [{
  json: {
    to: process.env.ALERT_EMAIL_TO || 'alerts@yourstore.com',
    subject: copy.email_subject || `${typeLabel}: ${alert.product_name}`,
    product_name: alert.product_name,
    current_stock: alert.current_stock,
    threshold: alert.threshold,
    alert_type: alert.alert_type,
    email_body: copy.email_body,
    email_preheader: copy.email_preheader,
    sms_copy: copy.sms,
    push_copy: copy.push_notification,
    internal_alert: copy.internal_alert,
    recommended_action: copy.recommended_action,
    type_label: typeLabel,
    dashboard_url: process.env.DASHBOARD_URL || 'http://localhost:3001/alerts'
  }
}];

